<template>
  <div class="notification-settings" role="region" aria-label="Notification Settings">
    <div class="card wellness-card mb-4">
      <div class="card-header wellness-header">
        <h3 class="mb-0">
          <i class="fas fa-bell" aria-hidden="true"></i>
          {{ $t('notificationSettings') }}
        </h3>
      </div>

      <div class="card-body wellness-body">
        <!-- Permission Status -->
        <div v-if="!hasPermission" class="alert alert-warning mb-4">
          <h5>{{ $t('enableNotifications') }}</h5>
          <p>{{ $t('enableNotificationsDesc') }}</p>
          <button @click="handleRequestPermission" class="btn btn-primary" :disabled="isLoading">
            <span v-if="isLoading" class="spinner-border spinner-border-sm mr-2"></span>
            {{ $t('enableNotifications') }}
          </button>
        </div>

        <div v-if="permissionState.denied" class="alert alert-danger mb-4">
          <h5>{{ $t('notificationsBlocked') }}</h5>
          <p>{{ $t('notificationsBlockedDesc') }}</p>
        </div>

        <!-- Simple Settings -->
        <div v-if="hasPermission" class="settings-section">
          <div class="form-check mb-3">
            <input
              class="form-check-input"
              type="checkbox"
              v-model="holidayAlertsEnabled"
              id="holidayAlerts"
            >
            <label class="form-check-label" for="holidayAlerts">
              {{ $t('holidayReminders') }}
            </label>
            <small class="form-text text-muted">{{ $t('holidayRemindersDesc') }}</small>
          </div>

          <div class="form-check">
            <input
              class="form-check-input"
              type="checkbox"
              v-model="dailyReminderEnabled"
              id="dailyReminder"
            >
            <label class="form-check-label" for="dailyReminder">
              {{ $t('dailyReminder') }}
            </label>
            <small class="form-text text-muted">{{ $t('dailyReminderDesc') }}</small>
          </div>
        </div>

        <!-- Status -->
        <div v-if="hasPermission" class="mt-4">
          <small class="text-muted">
            {{ $t('activeReminders') }}: {{ pendingCount }}
          </small>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, onMounted, watch } from 'vue';

const isLoading = ref(false);
const permissionState = ref({ granted: false, denied: false, pending: false });

const holidayAlertsEnabled = ref(false);
const dailyReminderEnabled = ref(false);

const hasPermission = computed(() => permissionState.value.granted);
const pendingCount = ref(0);

onMounted(async () => {
  await checkPermission();
  loadSettings();
});

watch(holidayAlertsEnabled, (newVal) => {
  if (newVal) {
    scheduleHolidayAlerts();
  } else {
    cancelHolidayAlerts();
  }
  saveSettings();
});

watch(dailyReminderEnabled, (newVal) => {
  if (newVal) {
    scheduleDailyReminder();
  } else {
    cancelDailyReminder();
  }
  saveSettings();
});

async function checkPermission() {
  try {
    const result = await Notification.requestPermission();
    permissionState.value = {
      granted: result === 'granted',
      denied: result === 'denied',
      pending: result === 'default'
    };
  } catch (error) {
    console.error('Permission check failed:', error);
  }
}

async function handleRequestPermission() {
  isLoading.value = true;
  try {
    await checkPermission();
  } finally {
    isLoading.value = false;
  }
}

function scheduleHolidayAlerts() {
  // Simple implementation - schedule alerts for upcoming holidays
  console.log('Scheduling holiday alerts...');
}

function cancelHolidayAlerts() {
  console.log('Cancelling holiday alerts...');
}

function scheduleDailyReminder() {
  // Simple daily reminder at 9 AM
  console.log('Scheduling daily reminder...');
}

function cancelDailyReminder() {
  console.log('Cancelling daily reminder...');
}

function loadSettings() {
  const settings = localStorage.getItem('notificationSettings');
  if (settings) {
    const parsed = JSON.parse(settings);
    holidayAlertsEnabled.value = parsed.holidayAlertsEnabled || false;
    dailyReminderEnabled.value = parsed.dailyReminderEnabled || false;
  }
}

function saveSettings() {
  const settings = {
    holidayAlertsEnabled: holidayAlertsEnabled.value,
    dailyReminderEnabled: dailyReminderEnabled.value
  };
  localStorage.setItem('notificationSettings', JSON.stringify(settings));
}
</script>

